// generar_252_medicamentos_dosis_por_dia.js
// CHIQUI Entre Señales — Medicamentos varias veces al día + UX de tomas
//
// IMPORTANTE: primero corre sql_252_dosis_por_dia.sql en Supabase
// (New snippet). Ese SQL:
//   1) Agrega dosis_por_dia (int, default 1) en medicamentos.
//   2) Agrega dosis_num (int, default 1) en medicamento_tomas.
//   3) Cambia UNIQUE(medicamento_id, fecha) por
//      UNIQUE(medicamento_id, fecha, dosis_num) — permite varias tomas
//      del mismo medicamento el mismo día.
//
// Tres mejoras en un paquete:
//
// 1) MEDICAMENTOS VARIAS VECES AL DÍA
//    - Modal de medicamento (nuevo / editar): campo "Tomas por día"
//      con selector 1-6, default 1, con nota "Ej. 'cada 12 horas' →
//      2 tomas al día".
//    - Registro diario, mini-modal: cada medicamento activo muestra
//      "Dosis 1 de 3" / "Dosis 2 de 3" según cuántas tomas ya se
//      registraron ese día. Al confirmar, la dosis se numera bien.
//    - Cuando se completan todas las dosis del día, la tarjeta del
//      medicamento se ve VERDE con "✓ 3 de 3 hoy" y queda deshabilitada
//      (no se puede marcar de más).
//    - Pre-selección más inteligente: al abrir el modal solo se
//      pre-marcan los medicamentos que AÚN tienen dosis pendientes.
//
// 2) HISTORIAL DE TOMAS DESPLEGABLE en Prevención
//    - La tarjeta del medicamento muestra "Historial · N tomas ⌄"
//      colapsable (default cerrado, se abre al tocar). Antes se
//      veían siempre las últimas 3 y "Ver todas" abría el resto —
//      con muchos tratamientos podía ser mucho ruido visual.
//    - Nuevo indicador PERMANENTE arriba del historial: puntos
//      circulares azules/grises con "2 de 3 hoy", visible siempre
//      que el medicamento esté activo, aunque el historial esté
//      cerrado. Comunica el progreso del día de un vistazo.
//
// 3) DASHBOARD "Próximos" — enfermedad → CONTROL VETERINARIO
//    - Cambia el título de "Enfermedades" a "Control veterinario".
//      Lo que ocurre próximamente es el control, no la enfermedad
//      en sí. El nombre de la enfermedad sigue en el subtítulo.
//    - La novedad de medicamentos del dashboard ahora considera
//      dosis por día: solo aparece si algún activo NO completó sus
//      dosis, y en el nombre del medicamento suma el progreso
//      "Rimadyl (1/2 hoy)" para que el tutor sepa cuánto falta.
//
// Uso:
//   1) SQL primero: sql_252_dosis_por_dia.sql → New snippet → Run
//   2) node generar_252_medicamentos_dosis_por_dia.js
//   3) git add . && commit && push

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/prevencion/page.tsx",
    base64: ""
  },
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/dashboard/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 3 archivos escritos.')
  console.log('Recuerda: SQL primero, luego git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
